+using GCCM.Common.SystemFramework;
+using NSubstitute;
+using ProjectSight.Common.Components;
+using ProjectSight.DataAccess.DMS;
+using System.Net;
+using static ProjectSight.Tests.Builders.TestDataBuilder;
+
+namespace ProjectSight.Tests.IntegrationTests.ExternalFileService
+{
+    /// <summary>
+    /// Targeted coverage tests for <see cref="ExternalFileSystem.DownloadExternalFileAndStoreInFMSAsync"/>.
+    /// The method downloads a file from an external URL to <c>WebFileUploadDirectory</c> via
+    /// <c>IExternalFileService.DownloadFileAsync</c>, then hands it off to
+    /// <c>DMSSystem.CreateDMSFileForAPIInternalAsync</c> which moves it into the FMS.
+    /// </summary>
+    [TestClass]
+    public class DownloadExternalFileAndStoreInFMSTests : RecordTestBase
+    {
+        private const string EXTERNAL_LOCATION = "https://example.com/test-file";
+
+        #region DownloadExternalFileAndStoreInFMSAsync
+
+        [TestMethod]
+        public async Task DownloadExternalFileAndStoreInFMSReturnsFalseWhenInputDataIsNull()
+        {
+            var requestedBy = GenerateRequestedByProject();
+            var error = new ErrorEncountered();
+
+            using (var portfolioDB = _dbHelperFactory.NewDBHelperPortfolio(requestedBy, requestedBy.ProjectID))
+            {
+                var jobStatus = new JobStatus { InputData = null };
+
+                var result = await new ExternalFileSystem().DownloadExternalFileAndStoreInFMSAsync(portfolioDB, jobStatus, "test-job", error, default);
+
+                result.Should().BeFalse("a null InputData means the request could not be deserialized");
+            }
+        }
+
+        [TestMethod]
+        public async Task DownloadExternalFileAndStoreInFMSDownloadsToWebFileUploadDirectoryThenStoresToFMS()
+        {
+            var requestedBy = GenerateRequestedByProject();
+            requestedBy.ExecuteJobsSynchronously = true;
+
+            var error = new ErrorEncountered();
+
+            using (var portfolioDB = _dbHelperFactory.NewDBHelperPortfolio(requestedBy, requestedBy.ProjectID))
+            {
+                var sourcePath = GetFilePath(TestFiles.UPLOAD_SMALLPDF);
+                var uploadsDir = portfolioDB.WebFileUploadDirectory;
+
+                var mockService = BuildDownloadStub(sourcePath);
+                var factory = Substitute.For<IExternalFileServiceFactory>();
+                factory.GetExternalFileService().Returns(mockService);
+
+                var uploadRequest = new ExternalFileUploadRequest
+                {
+                    ExternalLocation = EXTERNAL_LOCATION,
+                    FileName = GetFileNameWithExtension(TestFiles.UPLOAD_SMALLPDF),
+                    FolderId = GetRootFolderId().ToString()
+                };
+
+                var serverRequest = new ExternalFileUploadRequestServer(uploadRequest);
+
+                var jobStatus = new JobStatus { InputData = serverRequest };
+
+                var result = await new ExternalFileSystem(factory).DownloadExternalFileAndStoreInFMSAsync(portfolioDB, jobStatus, "test-job", error, default);
+
+                result.Should().BeTrue("the download and FMS storage should complete successfully");
+                error.Message.Should().BeNullOrEmpty();
+                serverRequest.FileRequest.Status.Should().Be(DMSFileRequest.Statuses.Success, "file request status is updated on success");
+                serverRequest.FileRequest.ClientFileName.Should().NotBeNullOrEmpty("FileSID of the created DMS file is recorded");
+
+                RecordNewFilePS(serverRequest.FileRequest.ClientFileName);
+
+                await mockService.Received(1).DownloadFileAsync(
+                    EXTERNAL_LOCATION,
+                    Arg.Is<string>(p => p.StartsWith(uploadsDir)),
+                    Arg.Any<IExceptionContext>(),
+                    Arg.Any<CancellationToken>());
+            }
+        }
+
+        #endregion // DownloadExternalFileAndStoreInFMSAsync
+
+        #region Helpers
+
+        private static IExternalFileService BuildDownloadStub(string sourceFilePath)
+        {
+            var service = Substitute.For<IExternalFileService>();
+
+            service.DownloadFileAsync(
+                    Arg.Any<string>(),
+                    Arg.Any<string>(),
+                    Arg.Any<IExceptionContext>(),
+                    Arg.Any<CancellationToken>())
+                .Returns(callInfo =>
+                {
+                    var destination = callInfo.ArgAt<string>(1);
+                    File.Copy(sourceFilePath, destination, overwrite: true);
+                    return Task.FromResult(new WebRequestResponse(EXTERNAL_LOCATION) { ResponseCode = HttpStatusCode.OK });
+                });
+
+            service.DeleteFileIfOurOwnAsync(
+                    Arg.Any<string>(),
+                    Arg.Any<IExceptionContext>(),
+                    Arg.Any<CancellationToken>())
+                .Returns(Task.FromResult(false));
+
+            return service;
+        }
+
+        #endregion // Helpers
+    }
+}

