+        private static System.Collections.Generic.HashSet<string> ReadZipEntryFileNames(string zipServerFileName)
+        {
+            var fileNames = new System.Collections.Generic.HashSet<string>(StringComparer.InvariantCultureIgnoreCase);
+
+            using (var fs = new FileStream(zipServerFileName, FileMode.Open, FileAccess.Read, FileShare.Read))
+            using (var archive = new ZipFile(fs))
+            {
+                foreach (ZipEntry entry in archive)
+                {
+                    if (entry.IsFile)
+                    {
+                        fileNames.Add(Path.GetFileName(entry.Name));
+                    }
+                }
+            }
+
+            return fileNames;
+        }
+
+        #endregion // Helpers
