+        [TestMethod]
+        public async Task SetAttachmentForFileLinkAsyncResolvesPhysicalPathForUploadedFile()
+        {
+            var link = await GetUploadedFileLinkPSAsync(TestFiles.UPLOAD_SAMPLEFILE);
+            link.SourceType = (int)FileLink.SourceTypes.Core; // File already uploaded
+            var reqBy = GenerateRequestedByProject();
+            var error = new ErrorEncountered();
