+        private async Task<(RFI Rfi, string FileName)> CreateRFIWithProjectSightFileLinkAsync(TestFiles file)
+        {
+            var fileLink = await GetUploadedFileLinkPSAsync(file);
+
+            var rfi = NewRFI();
+            rfi.FileLinks.Add(fileLink);
+
+            var savedRfi = await SaveRecordAsync(rfi);
+
+            return (savedRfi, fileLink.FileName);
