+
+        private string CopyTestFileToWebUploadDirectory(TestFiles file)
+        {
+            var sourcePath = GetFilePath(file);
+            var fileGuid = Global.CreateFileGUIDFromGUID(Guid.NewGuid());
+            var serverFileName = Path.Combine(GetWebFileUploadDirectory(ContextPortfolioId), fileGuid);
+
+            File.Copy(sourcePath, serverFileName);
+
+            return serverFileName;
+        }
+
+        private UploadFile BuildUploadFileForExternalExecutor(TestFiles file, string folderId, out string serverFileName)
+        {
+            var sourcePath = GetFilePath(file);
+            var fileGuid = Global.CreateFileGUIDFromGUID(Guid.NewGuid());
+            serverFileName = Path.Combine(GetWebFileUploadDirectory(ContextPortfolioId), fileGuid);
+            File.Copy(sourcePath, serverFileName);
+
+            return new UploadFile
+            {
+                GUID = fileGuid,
+                HasChanged = true,
+                Name = GetFileNameWithExtension(file),
+                FileType = Path.GetExtension(sourcePath),
+                ServerFileName = serverFileName,
+                DMSFolderID = folderId,
+                UnzipOnUpload = false,
+                FileSize = Global.CTIFileLen(serverFileName)
+            };
+        }
+
+        private static System.Collections.Generic.HashSet<string> ReadZipEntryFileNames(string zipServerFileName)
+        {
+            var fileNames = new System.Collections.Generic.HashSet<string>(StringComparer.InvariantCultureIgnoreCase);
+
+            using (var fs = new FileStream(zipServerFileName, FileMode.Open, FileAccess.Read, FileShare.Read))
+            using (var archive = new ZipFile(fs))
+            {
+                foreach (ZipEntry entry in archive)
+                {
+                    if (entry.IsFile)
+                    {
+                        fileNames.Add(Path.GetFileName(entry.Name));
+                    }
+                }
+            }
+
+            return fileNames;
+        }
+
+        #endregion // Helpers
