+using GCCM.Common.SystemFramework;
+using ProjectSight.Common.Components;
+using ProjectSight.DataAccess;
+using static ProjectSight.Tests.Builders.TestDataBuilder;
+
+namespace ProjectSight.Tests.IntegrationTests.FileLibrary
+{
+    /// <summary>
+    /// Targeted coverage tests for the <see cref="ProjectSight.WebAPI.Controllers.ApiControllerBase"/>
+    /// file-delivery methods: <c>DeliverRequestedContentAsync</c>, <c>DeliverPhotoAsync</c>,
+    /// <c>DeliverSpecificationAsync</c>, <c>DeliverDrawingAsync</c>, and <c>DeliverFileAsync</c>.
+    ///
+    /// Each test confirms that the underlying <c>ServeFile</c> / <c>FileStream</c> read is
+    /// exercised against a real file on the file-share — i.e. the filesystem IO path is live.
+    /// </summary>
+    [TestClass]
+    public class DeliverContentTests : RecordTestBase
+    {
+        #region DeliverRequestedContentAsync
+
+        /// <summary>
+        /// DeliverRequestedContentAsync opens the file stored at DMSFileRequest.ServerFileName
+        /// (in WebFileUploadDirectory) and streams it to the caller. A 200 OK response confirms
+        /// the FileStream read succeeded.
+        /// </summary>
+        [TestMethod]
+        public async Task DeliverRequestedContentServeFileReadsFromWebFileUploadDirectory()
+        {
+            var requestedBy = GenerateRequestedByProject();
+
+            // Place a test file in the uploads directory (the path DeliverRequestedContentAsync reads)
+            var uploadsDir = GetWebFileUploadDirectory(ContextPortfolioId);
+            var fileGuid = Global.CreateFileGUIDFromGUID(Guid.NewGuid());
+            var serverFileName = Path.Combine(uploadsDir, fileGuid);
+            File.Copy(GetFilePath(TestFiles.UPLOAD_SMALLPDF), serverFileName);
+
+            // Write a DMSFileRequest so the fetch/report endpoint can locate the file
+            var request = new DMSFileRequest
+            {
+                ClientFileName = "test-content.pdf",
+                ServerFileName = serverFileName,
+                Status = DMSFileRequest.Statuses.Success
+            };
+
+            var written = new DMSSystem().WriteFileRequest(request, requestedBy);
+            written.Should().BeTrue("file request must be persisted to DB");
+            request.RecordId.Should().BeGreaterThan(0, "WriteFileRequest must assign a RecordId");
+
+            try
+            {
+                File.Exists(serverFileName).Should().BeTrue("test file must be present in WebFileUploadDirectory before the HTTP call");
+
+                m_FetchClient ??= GetFetchClient();
+
+                // GET v1.0/{portfolio}/{project}/fetch/report/{id}
+                using var response = m_FetchClient.FetchReport(m_oPortfolioId, m_oProject.ProjectID, request.RecordId);
+                m_FetchClient.VerifyResponseIsOk();
+                response.Should().NotBeNull("DeliverRequestedContentAsync must stream the file when it exists");
+            }
+            finally
+            {
+                new DMSSystem().DeleteFileRequest(requestedBy, request.RecordId, false);
+                Global.KillAFile(serverFileName, true);
+            }
+        }
+
+        #endregion // DeliverRequestedContentAsync
+
+        #region DeliverPhotoAsync
+
+        /// <summary>
+        /// DeliverPhotoAsync calls PhotoManagementSystem.GetPhotoInfoAsync to resolve the file
+        /// path then opens it with ServeFile / FileStream. A 200 OK response confirms the
+        /// filesystem read against the photos directory succeeded.
+        /// </summary>
+        [TestMethod]
+        public async Task DeliverPhotoServeFileReadsFromPhotosDirectory()
+        {
+            // Upload a photo so it is stored on the file share
+            var album = CreatePhotoAlbum(Generate.String("Album"), m_RootAlbumId);
+            var photoId = await GetUploadedPhotoID(TestFiles.IRRITATED_JPG, album.PhotoAlbumID);
+            photoId.Should().BeGreaterThan(0, "photo must be uploaded successfully");
+
+            // Confirm the file exists on disk before the HTTP call
+            var info = await GetPhotoInfoAsync(photoId, album.PhotoAlbumID);
+            info.Should().NotBeNull("uploaded photo must have resolvable file info");
+            File.Exists(info.PhotoPath).Should().BeTrue("photo file must be present in the photos directory");
+
+            m_FetchClient ??= GetFetchClient();
+
+            // GET v1.0/{portfolio}/{project}/fetch/photo/{photoId}
+            using var response = await m_FetchClient.FetchPhotoAsync(m_oPortfolioId, m_oProject.ProjectID, photoId);
+            m_FetchClient.VerifyResponseIsOk();
+            response.Should().NotBeNull("DeliverPhotoAsync must stream the photo file when it exists");
+        }
+
+        #endregion // DeliverPhotoAsync
+
+        #region DeliverSpecificationAsync
+
+        /// <summary>
+        /// DeliverSpecificationAsync calls SpecificationSystem.GetSpecificationFileInfo (which
+        /// invokes ProjectSightDMSService.GetFMSDirectory) then streams the spec file with
+        /// ServeFile / FileStream. A 200 OK confirms both the directory creation path
+        /// (GetFMSDirectory) and the FileStream read are exercised against the file share.
+        /// </summary>
