+            var specSet = await UploadAndProcessSpecSetAsync(TestFiles.SPECSET_PDF_SMALL);
+            specSet = await PublishSpecSetAsync(specSet);
+            specSet.Specifications.Should().NotBeEmpty("spec set must contain at least one published section");
+
+            var specId = specSet.Specifications[0].SpecificationID;
+
+            // Confirm the FMS file is on disk before the HTTP call
+            var requestedBy = GenerateRequestedByProject();
+            var info = new SpecificationSystem().GetSpecificationFileInfo(specId, requestedBy);
+            info.Should().NotBeNull("published specification must have resolvable file info");
+            File.Exists(info.FilePath).Should().BeTrue("specification file must be present in the FMS directory");
+
+            m_FetchClient ??= GetFetchClient();
+
+            // GET v1.0/{portfolio}/{project}/fetch/specification/{specId}
+            using var response = await m_FetchClient.FetchSpecificationAsync(m_oPortfolioId, m_oProject.ProjectID, specId);
+            m_FetchClient.VerifyResponseIsOk();
+            response.Should().NotBeNull("DeliverSpecificationAsync must stream the specification file when it exists");
+        }
+
+        #endregion // DeliverSpecificationAsync
+
+        #region DeliverDrawingAsync
+
+        /// <summary>
+        /// DeliverDrawingAsync calls DrawingSystem.GetDrawingFileInfo to resolve the FMS path
+        /// then opens it with ServeFile / FileStream. A 200 OK confirms the filesystem read
+        /// against the FMS directory succeeded.
+        /// </summary>
