+            m_FetchClient ??= GetFetchClient();
+
+            // GET v1.0/{portfolio}/{project}/fetch/drawing/{drawingId}
+            using var response = await m_FetchClient.FetchDrawingAsync(m_oPortfolioId, m_oProject.ProjectID, drawingId);
+            m_FetchClient.VerifyResponseIsOk();
+            response.Should().NotBeNull("DeliverDrawingAsync must stream the drawing file when it exists");
+        }
+
+        #endregion // DeliverDrawingAsync
+
+        #region DeliverFileAsync
+
+        /// <summary>
+        /// DeliverFileAsync calls DMSSystem.GetAttachmentForFileDownloadAsync to resolve the
+        /// FMS path then opens it with ServeFile / FileStream. A 200 OK confirms the filesystem
+        /// read against the FMS directory succeeded.
+        /// </summary>
+        [TestMethod]
+        public void DeliverFileServeFileReadsFromFMSDirectory()
+        {
+            var file = UploadFilePS(TestFiles.UPLOAD_SMALLPDF);
+
+            // Confirm the FMS file is on disk before the HTTP call
+            var requestedBy = GenerateRequestedByProject();
+            var fmsDirectory = new ProjectSightDMSService(requestedBy).GetFMSDirectory();
+            var serverFileName = Path.Combine(fmsDirectory, Global.CreateFileGUIDFromGUID(file.GUID));
+            File.Exists(serverFileName).Should().BeTrue("DMS file must be present in FMS after upload");
+
+            m_FetchClient ??= GetFetchClient();
+
+            // GET v1.0/{portfolio}/{project}/fetch/file/{fileId}
+            using var response = m_FetchClient.FetchFile(m_oPortfolioId, m_oProject.ProjectID, file.FileID);
+            m_FetchClient.VerifyResponseIsOk();
+            response.Should().NotBeNull("DeliverFileAsync must stream the DMS file from FMS");
+        }
+
+        #endregion // DeliverFileAsync
+    }
+}
