diff --git a/Core/Tests/ProjectSight.Tests.ParallelIntegrationTests/ProjectExport/AnnotateDrawingSpecPDFsTests.cs b/Core/Tests/ProjectSight.Tests.ParallelIntegrationTests/ProjectExport/AnnotateDrawingSpecPDFsTests.cs
