@@ -0,0 +1,146 @@
+using ProjectSight.Common.Components;
+using static ProjectSight.Tests.Builders.TestDataBuilder;
+
+namespace ProjectSight.Tests.IntegrationTests.ProjectExport
+{
+    /// <summary>
+    /// Integration tests for <see cref="ExportAsBuilt.AnnotateDrawingSpecPDFsAsync"/>.
+    ///
+    /// Each test exercises the full annotation pipeline:
+    ///   Phase 1 (ExportRecordsAndFilesAsBuilt) — discovers records and writes the
+    ///   prerequisite txt/json files via DiscoverLinkedRecordsForAsBuilt / SaveDrawingSpecsToFiles.
+    ///   Phase 2 (AnnotateDrawingSpecPDFsAsync) — reads those files, calls
+    ///   DownloadHandler.PrepareAnnotateRecordsForAsBuiltAsync, which resolves resources via
+    ///   ResourceFile.ResolveAsync and produces annotated PDFs, then moves them to the export directory.
+    /// </summary>
+    [TestClass]
+    public class AnnotateDrawingSpecPDFsTests : RecordTestBase
+    {
+        private List<int> _createdRequestIds;
+
+        public override async Task CustomTestInitializeAsync()
+        {
+            await base.CustomTestInitializeAsync();
+            _createdRequestIds = new List<int>();
+        }
+
+        public override async Task CustomTestCleanupAsync()
+        {
+            RemoveCreatedExportRequests(_createdRequestIds);
+            await base.CustomTestCleanupAsync();
+        }
+
+        #region AnnotateDrawingSpecPDFsAsync — drawings
+
+        /// <summary>
+        /// Publishes a drawing, runs Phase 1 (writes drawingsToAnnotate.txt and related JSON files),
+        /// then calls AnnotateDrawingSpecPDFsAsync directly.
+        /// Asserts that PrepareAnnotateRecordsForAsBuiltAsync ran and produced a named annotated PDF
+        /// (ResourceFile.ResolveAsync resolves the drawing's FMS file as part of this pipeline).
+        /// </summary>
+        [TestMethod]
+        public async Task AnnotateDrawingSpecPDFsAsyncProducesAnnotatedPDFForPublishedDrawing()
+        {
+            var drawingSet = await CreateDrawingSetWithPublishedDrawingsAsync(TestFiles.UPLOAD_SMALLPDF_C1REV1);
+            drawingSet.Drawings.Should().NotBeEmpty("at least one drawing must be published");
+            var drawing = drawingSet.Drawings[0];
+
+            var exportId = await ExportRecordsAndFilesAsBuilt(new() { PrologTable.Types.Drawing }, false);
+            _createdRequestIds.Add(exportId);
+
+            var request = new ProjectExportSystem().ReadRequest(exportId);
+            request.Should().NotBeNull("export request must exist after Phase 1 setup");
+
+            var exportDir = ProjectExportSystem.GetRequestFolderPath(request);
+            using (var portfolioDB = _dbHelperFactory.NewDBHelperPortfolio(GenerateRequestedByProject(), ContextProjectID))
+            {
+                var helper = new ExportAsBuilt(request.Options);
+                await helper.AnnotateDrawingSpecPDFsAsync(portfolioDB, request, CancellationToken.None);
+            }
+
+            // MoveAnnotated places each annotated PDF at {exportDir}/{nomenclature}/{Number} - {Revision}.pdf
+            var expectedFilename = $"{drawing.Number} - {drawing.RevisionNumber}.pdf";
+            var annotatedPdf = Directory.GetFiles(exportDir, expectedFilename, SearchOption.AllDirectories);
+            annotatedPdf.Should().HaveCount(1, "one annotated PDF must be produced per drawing");
+        }
+
+        #endregion // AnnotateDrawingSpecPDFsAsync — drawings
+
+        #region AnnotateDrawingSpecPDFsAsync — specifications
+
+        /// <summary>
+        /// Publishes a specification set, runs Phase 1, then calls AnnotateDrawingSpecPDFsAsync directly.
+        /// Asserts that PrepareAnnotateRecordsForAsBuiltAsync ran and produced a named annotated PDF.
+        /// </summary>
+        [TestMethod]
+        public async Task AnnotateDrawingSpecPDFsAsyncProducesAnnotatedPDFForPublishedSpecification()
+        {
+            var specSet = await UploadAndProcessSpecSetAsync(TestFiles.SPECSET_PDF_SMALL);
+            specSet = await PublishSpecSetAsync(specSet);
+            specSet.Specifications.Should().NotBeEmpty("at least one specification section must be published");
+            var spec = specSet.Specifications[0];
+
+            var exportId = await ExportRecordsAndFilesAsBuilt(new() { PrologTable.Types.Specification }, false);
+            _createdRequestIds.Add(exportId);
+
+            var request = new ProjectExportSystem().ReadRequest(exportId);
+            request.Should().NotBeNull("export request must exist after Phase 1 setup");
+
+            var exportDir = ProjectExportSystem.GetRequestFolderPath(request);
+
+            using (var portfolioDB = _dbHelperFactory.NewDBHelperPortfolio(GenerateRequestedByProject(), ContextProjectID))
+            {
+                var helper = new ExportAsBuilt(request.Options);
+                await helper.AnnotateDrawingSpecPDFsAsync(portfolioDB, request, CancellationToken.None);
+            }
+
+            // First-published spec section gets revision identifier "00"
+            var expectedFilename = $"{spec.SpecSection} - 00.pdf";
+            var annotatedPdf = Directory.GetFiles(exportDir, expectedFilename, SearchOption.AllDirectories);
+            annotatedPdf.Should().HaveCount(1, "one annotated PDF must be produced per published specification section");
+        }
+
+        #endregion // AnnotateDrawingSpecPDFsAsync — specifications
+
+        #region ResourceFile.ResolveAsync — DMS file attachment
+
+        /// <summary>
+        /// Links a DMS file to a drawing annotation before export. During annotation, ResourceManager
+        /// iterates the file attachment and calls ResourceFile.ResolveAsync to locate the server file.
+        /// Asserts that the annotated PDF is still produced (i.e. ResolveAsync succeeded).
+        /// </summary>
+        [TestMethod]
+        public async Task AnnotateDrawingSpecPDFsAsyncResolvesAttachedDMSFileViaResourceFileResolveAsync()
+        {
+            var drawingSet = await CreateDrawingSetWithPublishedDrawingsAsync(TestFiles.UPLOAD_SMALLPDF_C1REV1);
+            var drawing = drawingSet.Drawings[0];
+
+            // Add a DMS file attachment via annotation — this creates a ResourceFile entry that
+            // ResourceFile.ResolveAsync must resolve during PrepareAnnotateRecordsForAsBuiltAsync
+            var fullDrawing = await ReadRecordAsync(drawing);
+            fullDrawing = await AddDrawingAnnotations(fullDrawing, 1);
+            await AddFileLinkViaAnnotationAsync(fullDrawing, await CreateFileLinkAsync(TestFiles.UPLOAD_SMALLPDF), 0);
+
+            var exportId = await ExportRecordsAndFilesAsBuilt(new() { PrologTable.Types.Drawing }, false, true);
+            _createdRequestIds.Add(exportId);
+
+            var request = new ProjectExportSystem().ReadRequest(exportId);
+            request.Should().NotBeNull("export request must exist after Phase 1 setup");
+
+            var exportDir = ProjectExportSystem.GetRequestFolderPath(request);
+
+            using (var portfolioDB = _dbHelperFactory.NewDBHelperPortfolio(GenerateRequestedByProject(), ContextProjectID))
+            {
+                var helper = new ExportAsBuilt(request.Options);
+                await helper.AnnotateDrawingSpecPDFsAsync(portfolioDB, request, CancellationToken.None);
+            }
+
+            // ResourceFile.ResolveAsync resolved the DMS attachment; annotated PDF produced for the drawing
+            var expectedFilename = $"{drawing.Number} - {drawing.RevisionNumber}.pdf";
+            var annotatedPdf = Directory.GetFiles(exportDir, expectedFilename, SearchOption.AllDirectories);
+            annotatedPdf.Should().HaveCount(1, "one annotated PDF must be produced for drawing with DMS file attachment resolved");
+        }
+
+        #endregion // ResourceFile.ResolveAsync — DMS file attachment
+    }
+}
