+using ProjectSight.Common.Components;
+using static ProjectSight.Tests.Builders.TestDataBuilder;
+
+namespace ProjectSight.Tests.IntegrationTests.Records.Drawings
+{
+    /// <summary>
+    /// Targeted coverage tests for <see cref="DrawingSystem.GetDrawingFileInfoAsync"/>.
+    /// The method resolves the FMS directory via <c>ProjectSightDMSService.GetFMSDirectory</c>
+    /// (creating it on demand) and returns minimal file metadata for the drawing revision.
+    /// </summary>
+    [TestClass]
+    public class GetDrawingFileInfoTests : RecordTestBase
+    {
+        private DrawingSystem _drawingSystem;
+
+        public override async Task CustomTestInitializeAsync()
+        {
+            await base.CustomTestInitializeAsync();
+            _drawingSystem = new DrawingSystem();
+        }
+
+        #region GetDrawingFileInfoAsync
+
+        [TestMethod]
+        public async Task GetDrawingFileInfoAsyncReturnsFMSDirectoryForPublishedDrawing()
+        {
+            var drawingSet = await CreateDrawingSetWithPublishedDrawingsAsync(TestFiles.UPLOAD_PDF_A1REV1);
+            var drawingId = drawingSet.Drawings[0].DrawingID;
+
+            var requestedBy = GenerateRequestedByProject();
+            var error = new ErrorEncountered();
+
+            var fileInfo = await _drawingSystem.GetDrawingFileInfoAsync(drawingId, requestedBy, error);
+
+            error.Message.Should().BeNullOrEmpty();
+            fileInfo.Should().NotBeNull();
+
+            using (new AssertionScope())
+            {
+                fileInfo.FMSDirectory.Should().NotBeNullOrEmpty("GetFMSDirectory is called to resolve the storage path");
+                Directory.Exists(fileInfo.FMSDirectory).Should().BeTrue("FMS directory is created on demand by GetFMSDirectory");
+                fileInfo.FileVersionGuid.Should().NotBe(Guid.Empty, "published drawing must have a persisted file version");
+            }
+        }
+
+        [TestMethod]
+        public async Task GetDrawingFileInfoAsyncFilePathPointsToExistingFileInFMSDirectory()
+        {
+            var drawingSet = await CreateDrawingSetWithPublishedDrawingsAsync(TestFiles.UPLOAD_PDF_A1REV1);
+            var drawingId = drawingSet.Drawings[0].DrawingID;
+
+            var requestedBy = GenerateRequestedByProject();
+            var error = new ErrorEncountered();
+
+            var fileInfo = await _drawingSystem.GetDrawingFileInfoAsync(drawingId, requestedBy, error);
+
+            fileInfo.Should().NotBeNull();
+            File.Exists(fileInfo.FilePath).Should().BeTrue("file version stored in FMSDirectory exists after publishing");
+        }
+
+        #endregion // GetDrawingFileInfoAsync
+    }
+}
